from dataclasses import dataclass
from datetime import date, timedelta
from typing import Optional

@dataclass
class ActivationCohortAnalysis:
    provisioning_date: date
    records: list[EmployeeAdoptionRecord]
    as_of: date

    def activation_by_day(self, max_days: int = 60) -> dict[int, float]:
        """Returns cumulative activation rate for each day post-provisioning."""
        total = len(self.records)
        if total == 0:
            return {}
        result = {}
        for day in range(1, max_days + 1):
            cutoff = self.provisioning_date + timedelta(days=day)
            activated = sum(
                1 for r in self.records
                if r.first_real_task_date and r.first_real_task_date <= cutoff
            )
            result[day] = activated / total * 100
        return result

    def non_activators(self) -> list[EmployeeAdoptionRecord]:
        """Employees provisioned >= 30 days ago who have never activated."""
        threshold = self.as_of - timedelta(days=30)
        return [
            r for r in self.records
            if r.provisioned_date and r.provisioned_date <= threshold
            and r.first_real_task_date is None
        ]

    def non_activator_breakdown(self) -> dict[str, int]:
        na = self.non_activators()
        by_bu: dict[str, int] = {}
        for r in na:
            by_bu[r.business_unit] = by_bu.get(r.business_unit, 0) + 1
        return dict(sorted(by_bu.items(), key=lambda x: x[1], reverse=True))

@dataclass
class EmbeddedUserAnalysis:
    records: list[EmployeeAdoptionRecord]
    as_of: date

    def embedded_users(self) -> list[EmployeeAdoptionRecord]:
        return [r for r in self.records if r.funnel_stage(self.as_of) in ("EMBEDDED", "ADVOCATE")]

    def embedded_by_role(self) -> dict[str, int]:
        embedded = self.embedded_users()
        by_role: dict[str, int] = {}
        for r in embedded:
            by_role[r.role] = by_role.get(r.role, 0) + 1
        return dict(sorted(by_role.items(), key=lambda x: x[1], reverse=True))

    def embedded_by_bu(self) -> dict[str, float]:
        """Embedded rate per BU (embedded / all in BU)."""
        bu_total: dict[str, int] = {}
        bu_embedded: dict[str, int] = {}
        for r in self.records:
            bu_total[r.business_unit] = bu_total.get(r.business_unit, 0) + 1
            if r.funnel_stage(self.as_of) in ("EMBEDDED", "ADVOCATE"):
                bu_embedded[r.business_unit] = bu_embedded.get(r.business_unit, 0) + 1
        return {
            bu: bu_embedded.get(bu, 0) / total * 100
            for bu, total in bu_total.items()
        }

    def top_bu_for_case_studies(self, top_n: int = 3) -> list[str]:
        """BUs with highest embedded rate — best candidates for case studies."""
        rates = self.embedded_by_bu()
        return sorted(rates, key=lambda bu: rates[bu], reverse=True)[:top_n]

from dataclasses import dataclass
from typing import Callable

@dataclass
class FunnelDiagnostic:
    funnel: 'AdoptionFunnel'

    def diagnose(self) -> list[dict]:
        r = self.funnel.funnel_report()
        issues = []

        prov_pct = r["provisioned"]["pct_of_eligible"]
        if prov_pct < 80:
            issues.append({
                "stage": "PROVISIONING",
                "severity": "HIGH" if prov_pct < 60 else "MEDIUM",
                "finding": f"Only {prov_pct:.0f}% of eligible staff provisioned",
                "next_action": "Pull provisioning step-by-step funnel from IT system; identify highest abandonment step",
            })

        act_pct = r["activated"]["pct_of_provisioned"]
        if act_pct < 50:
            issues.append({
                "stage": "ACTIVATION",
                "severity": "HIGH" if act_pct < 30 else "MEDIUM",
                "finding": f"Only {act_pct:.0f}% of provisioned staff have activated",
                "next_action": "Run 2-question survey to non-activators: what stopped you? what would help?",
            })

        ret_pct = r["retained"]["pct_of_activated"]
        if ret_pct < 40:
            issues.append({
                "stage": "RETENTION",
                "severity": "HIGH" if ret_pct < 25 else "MEDIUM",
                "finding": f"Only {ret_pct:.0f}% of activated users retained at 90 days",
                "next_action": "Analyse first-session tasks of non-retainers; check for common failure patterns",
            })

        return issues

# Usage: instantiate with a populated AdoptionFunnel and call diagnose()
